void fb_init() {
    fb_width = 720;
    fb_height = 1280;
    /* fb_cursor_x = 0; */
    /* fb_cusror_y = 0; */
}

void fb_init_addres(void *address) {
    fb = address;
}

void fb_get_pixel(u32 x, u32 y, u8* r, u8* g, u8* b) {
    u32 offset = (x + y * fb_width) * 3;
    *r = fb[offset + 0];
    *g = fb[offset + 1];
    *b = fb[offset + 2];
}

void fb_set_pixel(u32 x, u32 y, u8 r, u8 g, u8 b) {
    u32 offset = (x + y * fb_width) * 3;
    fb[offset + 0] = r;
    fb[offset + 1] = g;
    fb[offset + 2] = b;
}

void fb_blit(u32 X, u32 Y, u32 image_width, u32 image_height, u8* image) {
    for (u32 x = 0; x < image_width; x++) {
        for (u32 y = 0; y < image_height; y++) {
            fb[((x + X) + (y + Y) * fb_width) * 3 + 0] = image[(y * image_width + x) * 3 + 0];
            fb[((x + X) + (y + Y) * fb_width) * 3 + 1] = image[(y * image_width + x) * 3 + 1];
            fb[((x + X) + (y + Y) * fb_width) * 3 + 2] = image[(y * image_width + x) * 3 + 2];
        }
    }

    /* for (u32 y = 0; y < image_height; y++) { */
    /*     memcpy(fb + (Y + y) * fb_width * 3 + X, image + y * image_width * 3, image_width * 3); */
    /* } */
}

void fb_draw_char(u32 x, u32 y, u8 ch) {
    fb_blit(x * char_width, y * char_height, char_width, char_height, char_bitmaps[ch]);
}

void fb_put_char(u8 ch) {
    fb_blit(fb_cursor_x++ * char_width, fb_cursor_y * char_height, char_width, char_height, char_bitmaps[ch]);

    if (fb_cursor_x >= fb_width / char_width) {
        fb_cursor_y++;
        fb_cursor_x = 0;
    }
}
